// Refresca public.cartera con TODAS las facturas de Siigo que tengan saldo > 0.
// La cartera NO es por periodo: es la foto de lo que se debe HOY (incluye deuda vieja).
// Se hace en workflow programado porque barrer ~10.6k facturas toma minutos.
const token = $('Auth Siigo').first().json.access_token;
const SH  = { Authorization: 'Bearer ' + token, 'Partner-Id': 'n8nApp' };
const SB  = 'https://wavqyesyqqmawjfaztvb.supabase.co';
const KEY = '__SUPABASE_SERVICE_ROLE__';
const H   = { apikey: KEY, Authorization: 'Bearer ' + KEY };
const http = (o) => this.helpers.httpRequest(o);

// Envoltura que NUNCA lanza: {ok,status,data}. Siigo tiene hipos intermitentes.
async function safe(o, tries) {
  tries = tries || 3;
  let last = 0, msg = '';
  for (let i = 0; i < tries; i++) {
    try { return { ok:true, data: await http(o) }; }
    catch (e) {
      msg = String((e && e.message) || e);
      const m = /\b(\d{3})\b/.exec(msg);
      last = Number((e && (e.httpCode || e.statusCode)) || (e && e.cause && e.cause.statusCode) || (m && m[1]) || 0);
      if (i === tries - 1) return { ok:false, status:last, error:msg };
      await new Promise(r => setTimeout(r, 1500 * (i + 1)));
    }
  }
  return { ok:false, status:last, error:msg };
}

// Paginado EN PARALELO (de a 5). En serie, ~110 paginas a 2-18s c/u se pasaban
// de los 300s de limite del Code node y el refresco moria por timeout.
const CONC = 5;
let fallos = 0;

async function paginar(urlDe) {
  const first = await safe({ method:'GET', json:true, headers:SH, url: urlDe(1) });
  if (!first.ok) { fallos++; return []; }
  const tot = ((first.data || {}).pagination || {}).total_results || 0;
  const out = ((first.data || {}).results || []).slice();
  const pages = [];
  for (let p = 2; p <= Math.ceil(tot / 100); p++) pages.push(p);
  for (let i = 0; i < pages.length; i += CONC) {
    const res = await Promise.all(pages.slice(i, i + CONC)
      .map(p => safe({ method:'GET', json:true, headers:SH, url: urlDe(p) })));
    for (const r of res) {
      if (!r.ok) { fallos++; continue; }
      for (const x of ((r.data || {}).results || [])) out.push(x);
    }
  }
  return out;
}

// La serie FV-2 de exportacion NO sale en el listado estandar -> pasada aparte.
const a = await paginar(p => 'https://api.siigo.com/v1/invoices?page=' + p + '&page_size=100');
const b = await paginar(p => 'https://api.siigo.com/v1/invoices?document_id=30537&page=' + p + '&page_size=100');
const map = {};
for (const i of a.concat(b)) map[i.id] = i;
const all = Object.values(map);

// El listado de facturas NO trae customer.name (solo identification) -> catalogo aparte.
const custMap = {};
for (const c of await paginar(p => 'https://api.siigo.com/v1/customers?page=' + p + '&page_size=100')) {
  const id = String(c.identification || '').replace(/[^0-9]/g, '');
  const nm = Array.isArray(c.name) ? c.name.filter(Boolean).join(' ') : String(c.name || '');
  // Preferir el nombre real; el commercial_name suele venir como "No aplica".
  let com = (c.commercial_name || '').trim();
  if (/^(no aplica|n\/a|na|ninguno|-)$/i.test(com)) com = '';
  if (id) custMap[id] = nm || com || id;
}

// FAIL-SAFE: este workflow BORRA y reinserta la tabla. Si el barrido quedo
// incompleto, escribiriamos una cartera falsa (facturas vivas desaparecidas).
if (fallos > 0) {
  return [{ json: { alerta: 'fallaron ' + fallos + ' paginas de Siigo - NO se toco la tabla',
                    facturas_leidas: all.length } }];
}

function isNIT(raw) {
  const s = String(raw || '').trim();
  if (/^[0-9]{8,9}-[0-9]$/.test(s)) return true;
  const d = s.replace(/[^0-9]/g, '');
  return (d.length === 9 || d.length === 10) &&
         /^(800|811|812|813|820|830|832|860|890|891|892|899|900|901|902)/.test(d);
}
const KW = /(s\.?a\.?s\.?|ltda\.?|factura|corp|inc|empresa|group|grupo|distribu|comercial|industria|soluciones|servicios)/i;
function nameOf(c) { const n = c && c.name; return Array.isArray(n) ? n.join(' ') : String(n || ''); }
function canalOf(inv) {
  const cc = Number(inv.cost_center);
  if (cc === 315) return 'export';
  if (cc === 166) return 'b2b';
  if (cc === 168) { const cu = inv.customer || {}; return (isNIT(cu.identification) || KW.test(nameOf(cu))) ? 'b2b' : 'b2c'; }
  return 'otro';   // planta / admin: igual entran, la cartera es toda la plata por cobrar
}
const HOY = new Date();
const dias = (d) => Math.floor((HOY - new Date(d)) / 86400000);
const bucket = (x) => x > 180 ? '>180' : x > 120 ? '>120' : x > 90 ? '>90' : x > 31 ? '>31' : 'por_vencer';

const rows = [];
for (const inv of all) {
  const bal = Number(inv.balance || 0);
  if (!(bal > 0)) continue;
  const cur = inv.currency || {};
  const fx  = Number(cur.exchange_rate || 1);
  const tot = Number(inv.total || 0);
  // TRAMPA SIIGO: en moneda extranjera el `total` viene en la MONEDA ORIGINAL pero el
  // `balance` viene SIEMPRE en COP. Probado con FV-2-928: total 2.522,47 EUR y balance
  // 966.899,01 (383x el total) -> imposible que sea EUR. Por eso el saldo NO se convierte.
  // (Multiplicarlo por la tasa inflaba la cartera a $4.253 millones; y una heuristica
  // intermedia "si cabe en el total, es moneda original" le sumaba $3,1M de mas a
  // FV-2-974, cuyo saldo real son 720 pesos de residuo.)
  const saldo    = bal;
  const totalCop = fx !== 1 ? tot * fx : tot;
  const d  = dias(inv.date);
  const cu = inv.customer || {};
  rows.push({
    numero: inv.name || inv.id,
    inv_id: inv.id,
    fecha: String(inv.date || '').slice(0, 10),
    cliente: custMap[String(cu.identification || '').replace(/[^0-9]/g, '')] ||
             nameOf(cu) || String(cu.identification || ''),
    nit: String(cu.identification || ''),
    canal: canalOf(inv),
    moneda: cur.code || 'COP',
    total_cop: Math.round(totalCop * 100) / 100,
    saldo_cop: Math.round(saldo * 100) / 100,
    dias: d,
    bucket: bucket(d)
  });
}

// Reemplazo total: la cartera es un estado, no un historico acumulable.
await http({ method:'DELETE', headers: Object.assign({}, H, { Prefer:'return=minimal' }),
  url: SB + '/rest/v1/cartera?numero=neq.__ninguno__' });
for (let i = 0; i < rows.length; i += 200) {
  await http({ method:'POST', json:true,
    headers: Object.assign({}, H, { 'Content-Type':'application/json', Prefer:'return=minimal' }),
    url: SB + '/rest/v1/cartera', body: rows.slice(i, i + 200) });
}
const total = rows.reduce((s, r) => s + r.saldo_cop, 0);
return [{ json: { ok:true, facturas: rows.length, total_cartera: Math.round(total),
                  revisadas: all.length, actualizado: new Date().toISOString() } }];

// Sirve la cartera ya calculada (tabla public.cartera) al dashboard.
// Rapido: solo lee Supabase, no toca Siigo.
const SB  = 'https://wavqyesyqqmawjfaztvb.supabase.co';
const KEY = '__SUPABASE_SERVICE_ROLE__';
const H   = { apikey: KEY, Authorization: 'Bearer ' + KEY };
const http = (o) => this.helpers.httpRequest(o);

const rows = await http({ method:'GET', json:true, headers:H,
  url: SB + '/rest/v1/cartera?select=*&order=saldo_cop.desc&limit=5000' });
const facturas = Array.isArray(rows) ? rows : [];

const num = (x) => Number(x || 0);
const sumBucket = (b) => facturas.filter(f => f.bucket === b).reduce((s, f) => s + num(f.saldo_cop), 0);

const resumen = {
  totalDeuda: Math.round(facturas.reduce((s, f) => s + num(f.saldo_cop), 0)),
  facturas: facturas.length,
  masde180:  Math.round(sumBucket('>180')),
  masde120:  Math.round(sumBucket('>120')),
  masde90:   Math.round(sumBucket('>90')),
  masde31:   Math.round(sumBucket('>31')),
  porVencer: Math.round(sumBucket('por_vencer'))
};

// Agrupado por cliente (lo que pinta la tabla de aging)
const byCli = {};
for (const f of facturas) {
  const k = f.nit || f.cliente || '?';
  if (!byCli[k]) byCli[k] = { cliente: f.cliente, nit: f.nit, canal: f.canal, facturas: 0,
                              deudaTotal: 0, masde180: 0, masde120: 0, masde90: 0, masde31: 0, porVencer: 0 };
  const c = byCli[k];
  c.facturas += 1;
  c.deudaTotal += num(f.saldo_cop);
  if (f.bucket === '>180') c.masde180 += num(f.saldo_cop);
  else if (f.bucket === '>120') c.masde120 += num(f.saldo_cop);
  else if (f.bucket === '>90') c.masde90 += num(f.saldo_cop);
  else if (f.bucket === '>31') c.masde31 += num(f.saldo_cop);
  else c.porVencer += num(f.saldo_cop);
}
const porCliente = Object.values(byCli)
  .map(c => ({ ...c, deudaTotal: Math.round(c.deudaTotal), masde180: Math.round(c.masde180),
               masde120: Math.round(c.masde120), masde90: Math.round(c.masde90),
               masde31: Math.round(c.masde31), porVencer: Math.round(c.porVencer) }))
  .sort((a, b) => b.deudaTotal - a.deudaTotal);

const actualizado = facturas.length
  ? facturas.map(f => f.actualizado_en).sort().slice(-1)[0]
  : null;

return [{ json: { resumen, porCliente, facturas, actualizado_en: actualizado,
                  base: 'saldo real con IVA, en COP, todas las facturas abiertas (sin filtro de fecha)' } }];

